#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Ques{
    int id,p,a;
}q[N],b[N];

struct Node{
    int lc,rc,sum;
}t[N*20];

bool cmp(Ques x,Ques y){
    return x.id<y.id;
}

int n,m,a[N],p[N],root[N],tot,c[N];
long long ans[N];

void modify(int p,int q,int l,int r,int x){
    if(l==r){
        t[p].sum=t[q].sum+1;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid){
        t[p].lc=++tot;
        t[p].rc=t[q].rc;
        modify(t[p].lc,t[q].lc,l,mid,x);
    }else{
        t[p].rc=++tot;
        t[p].lc=t[q].lc;
        modify(t[p].rc,t[q].rc,mid+1,r,x);
    }
    t[p].sum=t[t[p].lc].sum+t[t[p].rc].sum;
}

int query(int p,int q,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[p].sum-t[q].sum;
    int mid=l+r>>1,res=0;
    if(x<=mid) res+=query(t[p].lc,t[q].lc,l,mid,x,y);
    if(y>mid) res+=query(t[p].rc,t[q].rc,mid+1,r,x,y);
    return res;
}

void add(int x,int k){
    for(;x<=n;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void del(int x){
    for(;x<=n && c[x];x+=(x&(-x)))
        c[x]=0;
}

void CDQ(int l,int r){
    if(l==r) return;
    int mid=l+r>>1;
    CDQ(l,mid);
    CDQ(mid+1,r);
    for(int i=mid+1,j=l;i<=r;i++){
        while(j<=mid && q[j].p<q[i].p){
            add(n-q[j].a+1,1);
            j++;
        }
        ans[q[i].id]+=ask(n-q[i].a+1);
    }
    for(int i=l;i<=mid;i++)
        del(n-q[i].a+1);
    for(int i=l,j=mid+1;i<=mid || j<=r;)
        if(i<=mid && (j>r || q[i].p<q[j].p))
            b[i-l+j-mid+l-1]=q[i],i++;
        else
            b[i-l+j-mid+l-1]=q[j],j++;
    for(int i=l;i<=r;i++)
        q[i]=b[i];
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        p[a[i]]=i;
        root[i]=++tot;
        modify(root[i],root[i-1],1,n,a[i]);
    }
    for(int i=1;i<=n;i++)
        ans[0]+=query(root[i],0,1,n,a[i]+1,n);
    for(int i=1;i<=m;i++){
        scanf("%d",&q[i].a);
        q[i].id=i,q[i].p=p[q[i].a];
        ans[i]-=query(root[q[i].p-1],0,1,n,q[i].a,n)+query(root[n],root[q[i].p],1,n,1,q[i].a);
    }
    CDQ(1,m);
    sort(q+1,q+m+1,cmp);
    for(int i=1;i<=m;i++)
        q[i].p=n-q[i].p+1,q[i].a=n-q[i].a+1;
    CDQ(1,m);
    for(int i=1;i<=m;i++)
        ans[i]+=ans[i-1];
    for(int i=0;i<m;i++)
        printf("%lld\n",ans[i]);
    return 0;
}
